        try_files /wp-includes/ms-files.php =404;
        access_log off;
        log_not_found off;
        expires max;
    }

    # WordPress Multisite: redirect /subsite/wp-admin to /subsite/wp-admin/
    location ~ ^/[_0-9a-zA-Z-]+/wp-admin$ {
        return 301 $scheme://$http_host$request_uri/;
    }

    # WordPress Multisite: rewrite /subsite/wp-admin/* to /wp-admin/*
    location ~ ^/[_0-9a-zA-Z-]+/(wp-admin/.*)$ {
        rewrite ^/[_0-9a-zA-Z-]+/(wp-admin/.*) /$1 last;
    }

    # WordPress Multisite: rewrite /subsite/wp-*.php to /wp-*.php
    location ~ ^/[_0-9a-zA-Z-]+/(wp-[^/]+\.php)$ {
        rewrite ^/[_0-9a-zA-Z-]+/(wp-[^/]+\.php)$ /$1 last;
    }

    # WordPress Multisite: rewrite /subsite/wp-includes/* to /wp-includes/*
    location ~ ^/[_0-9a-zA-Z-]+/(wp-includes/.+)$ {
        rewrite ^/[_0-9a-zA-Z-]+/(wp-includes/.+) /$1 last;
    }

    # WordPress Multisite: rewrite /subsite/wp-content/* to /wp-content/*
    location ~ ^/[_0-9a-zA-Z-]+/(wp-content/.+)$ {
        rewrite ^/[_0-9a-zA-Z-]+/(wp-content/.+) /$1 last;
    }

    # WordPress permalinks
    location / {
        try_files $uri $uri/ /index.php?$args;
    }

    # Static files caching
    # DEVE vir APÓS as regras multisite para que rewrites sejam processados primeiro
    location ~* \.(?:js|css|png|jpg|jpeg|gif|svg|woff2?|ttf|eot)$ {
        expires 1y;
        add_header Cache-Control "public, immutable";
        try_files $uri =404;
    }

    # Bloquear indexacao de PDFs pelo Google
    location ~* \.pdf$ {
        add_header X-Robots-Tag "noindex, nofollow" always;
        try_files $uri =404;
    }

    # Security restrictions
    location ~ /\.ht { deny all; }
    location ~* /(?:wp-config\.php|readme\.html|license\.txt)$ { deny all; }

    # PHP processing with SSL support
    location ~ \.php$ {
        fastcgi_param HTTPS $fastcgi_https;
        try_files $uri =404;
        include /etc/nginx/snippets/php-fpm.conf;
    }
}

